import React from 'react';
import PageLogo from '../Logo/GnuLinuxLogo.svg';
import HeaderInfoBackgroundImage from '../Background/HeaderInfoBackgroundImage.jpg';
import HeaderInfoGitHubLogo from '../Logo/GitHubLogo.svg';

import '../HeaderInfo.css';

class HeaderInfo extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      domainLogo: props.domainLogo || PageLogo,
      currentPageName: props.currentPageName || '',
      backgroundImage: props.backgroundImage || HeaderInfoBackgroundImage,
      githubLogo: props.githubLogo || HeaderInfoGitHubLogo,
      githubURL: props.githubURL || "www.github.com",
      githubPagesURL: props.githubPagesURL || "www.github.com",
      domainName: props.domainName || "www.unix69.githubio.com",
      pageName: props.pageName || "Unix69",
      HeaderInfoClass: props.headerInfoClass || "header-info",
      headerInfoBackgroundImageClass: props.headerInfoBackgroundImageClass || "header-info-background-image",
      headerInfoDomainInfoClass: props.headerInfoDomainInfoClass || "header-info-domain-info",
      headerInfoDomainInfoDomainUrlClass: props.headerInfoDomainInfoDomainUrlClass || "header-info-domain-info-domain-url",
      headerInfoDomainInfoDomainLogoClass: props.headerInfoDomainInfoDomainLogoClass || "header-info-domain-info-domain-logo",
      headerInfoGitHubInfoClass: props.headerInfoGitHubInfoClass || "header-info-github-info",
      headerInfoGitHubInfoGitHubUrlClass: props.headerInfoGitHubInfoGitHubUrlClass || "header-info-github-info-github-url",
      headerInfoGitHubInfoGitHubPagesUrlClass: props.headerInfoGitHubInfoGitHubPagesUrlClass || "header-info-github-info-github-pages-url",
      headerInfoGitHubInfoGitHubLogoClass: props.headerInfoGitHubInfoGitHubLogoClass || "header-info-github-info-github-logo",
      headerInfoGitHubInfoGitHubPagesLogoClass: props.headerInfoGitHubInfoGitHubPagesLogoClass || "header-info-github-info-github-pages-logo"
    };
  }

  render() {
    return (<section class={this.state.headerInfoClass}>
              <section class={this.state.headerDomainInfoClass}>
                  <img src={this.state.domainLogo} alt="Domain Logo" className={this.state.headerInfoDomainInfoLogoClass}/>
                  <a href={this.state.domainName} class={this.state.headerInfoDomainInfoURLClass}>{this.state.pageName}</a>
                  {this.state.currentPageName}
              </section>
              <section class={this.state.headerGitHubInfoClass}>                 
                  <a href={this.state.githubURL} class={this.state.headerInfoGitHubInfoGitHubURLClass}/>
                  <img src={this.state.githubLogo} alt="GitHub Logo" class={this.state.headerInfoGitHubInfoGitHubLogoClass}/>
                  <a href={this.state.githubPagesURL} class={this.state.headerInfoGitHubInfoGitHubPagesURLClass}>{this.state.githubPagesURL}</a>
              </section>
            </section>
    );
  }
}

export default HeaderInfo;
